import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const files = [
  "assets/js/config.js",
  "assets/js/data.js",
  "assets/js/media-service.js",
  "assets/js/app.js",
];

function transform(source) {
  return source
    .replace(/^import .*?;\s*$/gm, "")
    .replace(/\bexport\s+(?=(?:const|let|var|async\s+function|function|class)\b)/g, "");
}

const parts = [];
for (const file of files) {
  parts.push(`\n/* ---- ${file} ---- */\n${transform(await readFile(path.join(root, file), "utf8"))}`);
}

const bundle = `/* Generated by scripts/build-bundle.mjs. Edit the source modules, then run npm run build. */\n(() => {\n  "use strict";\n${parts.join("\n")}\n})();\n`;
await writeFile(path.join(root, "assets/js/site.bundle.js"), bundle);
console.log(`Built assets/js/site.bundle.js (${bundle.length.toLocaleString()} bytes)`);
